import React, { useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Input, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { bhService } from '../../../services/bh/bhService';
import { DocumentFormHeader } from '../../../components/layout';
import df from '../../../styles/documentForm.module.css';

const DonHangFormPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const isEdit = Boolean(id);
  const isNew = !isEdit;
  const navigate = useNavigate();
  const dispatch = useAppDispatch();
  const [orderDate, setOrderDate] = useState(new Date().toISOString().slice(0, 10));
  const [customerId, setCustomerId] = useState('');
  const [description, setDescription] = useState('');
  const [loading, setLoading] = useState(isEdit);
  const [saving, setSaving] = useState(false);

  React.useEffect(() => {
    if (!id) return;
    let cancelled = false;
    const t = setTimeout(() => {
      bhService.getOrder(id)
        .then(o => {
          if (!cancelled) {
            setOrderDate(o.orderDate.slice(0, 10));
            setCustomerId(o.customerId);
            setDescription(o.description ?? '');
          }
        })
        .catch(err => { if (!cancelled) dispatch(addToast({ message: err?.message ?? 'Lỗi', type: 'error' })); })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [id, dispatch]);

  const handleSave = async () => {
    if (!customerId) {
      dispatch(addToast({ message: 'Nhập customerId (Guid)', type: 'error' }));
      return;
    }
    setSaving(true);
    try {
      const line = { materialCode: 'SP001', unitCode: 'Cai', quantity: 1, unitPrice: 0, amount: 0 };
      if (isEdit && id) {
        await bhService.updateOrder(id, { description, lines: [line] });
        dispatch(addToast({ message: 'Cập nhật đơn hàng thành công', type: 'success' }));
      } else {
        await bhService.createOrder({ orderDate, customerId, description, lines: [line] });
        dispatch(addToast({ message: 'Tạo đơn hàng thành công', type: 'success' }));
      }
      navigate('/bh/dh');
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Lưu thất bại', type: 'error' }));
    } finally {
      setSaving(false);
    }
  };

  if (loading) return <div className={df.loading}>Đang tải...</div>;

  return (
<div className={df.page}>
      <DocumentFormHeader
        onBack={() => navigate('/bh/dh')}
        title={isEdit ? 'Sửa đơn hàng' : 'Tạo đơn hàng'}
        isNew={isNew}
        saving={saving}
        saveLabel="Tạo đơn hàng"
        saveEditLabel="Lưu thay đổi"
        onSave={handleSave}
      />
      <div className={df.section}>
        <h2 className={df.sectionTitle}>Thông tin đơn hàng</h2>
        <div className={df.row4}>
          <div className={df.field}>
            <label className={df.label}>Ngày đặt</label>
            <Input type="date" value={orderDate} onChange={e => setOrderDate(e.target.value)} />
          </div>
          <div className={df.field}>
            <label className={df.label}>Customer ID (Guid)</label>
            <Input value={customerId} onChange={e => setCustomerId(e.target.value)} disabled={isEdit} />
          </div>
          <div className={df.field}>
            <label className={df.label}>Diễn giải</label>
            <Input value={description} onChange={e => setDescription(e.target.value)} />
          </div>
        </div>
      </div>
    </div>
  );
};

export default DonHangFormPage;
